def escape_delimiters(s):
    result = []
    for ch in s:
        if ch == '\\':
            result.append('\\\\')
        elif ch == '|':
            result.append('\\|')
        else:
            result.append(ch)
    return ''.join(result)

def run_length_encode(s):
    if not s:
        return ""
    result = []
    prev = s[0]
    count = 1
    for ch in s[1:]:
        if ch == prev:
            count += 1
        else:
            result.append(str(count) + prev)
            prev = ch
            count = 1
    result.append(str(count) + prev)
    return ''.join(result)

def split_csv_line(line):
    fields, field, i, n, in_q = [], [], 0, len(line), False
    while i < n:
        c = line[i]
        if in_q:
            if c == '"':
                if i + 1 < n and line[i + 1] == '"':
                    field.append('"')
                    i += 1
                else:
                    in_q = False
            else:
                field.append(c)
        elif c == '"':
            in_q = True
        elif c == ',':
            fields.append(''.join(field))
            field = []
        else:
            field.append(c)
        i += 1
    fields.append(''.join(field))
    return fields

def parse_key_value_pairs(s):
    result = {}
    for segment in s.split(';'):
        segment = segment.strip()
        if not segment:
            continue
        if '=' not in segment:
            continue
        key, value = segment.split('=', 1)
        result[key.strip()] = value.strip()
    return result

