def is_balanced_brackets(s):
    pairs = {')': '(', ']': '[', '}': '{'}
    opens = set(pairs.values())
    stack = []
    for ch in s:
        if ch in opens:
            stack.append(ch)
        elif ch in pairs:
            if not stack or stack.pop() != pairs[ch]:
                return False
    return len(stack) == 0

def tokenize_alnum_words(s):
    tokens = []
    current = []
    for ch in s:
        if ch.isalnum():
            current.append(ch)
        else:
            if current:
                tokens.append(''.join(current))
                current = []
    if current:
        tokens.append(''.join(current))
    return tokens

def day_of_year(year, month, day):
    days_in_month = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
    leap = (year % 4 == 0 and year % 100 != 0) or (year % 400 == 0)
    if leap:
        days_in_month[1] = 29
    return sum(days_in_month[:month - 1]) + day

def add_days(year, month, day, delta_days):
    def is_leap(y):
        return (y % 4 == 0 and y % 100 != 0) or (y % 400 == 0)
    def days_in_month(y, m):
        dim = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
        return 29 if (m == 2 and is_leap(y)) else dim[m - 1]
    y, m, d = year, month, day + delta_days
    while d < 1:
        m -= 1
        if m < 1:
            m, y = 12, y - 1
        d += days_in_month(y, m)
    while d > days_in_month(y, m):
        d -= days_in_month(y, m)
        m += 1
        if m > 12:
            m, y = 1, y + 1
    return (y, m, d)

def banker_round_cents(tenths_of_cent):
    whole, rem = divmod(tenths_of_cent, 10)
    if rem < 5:
        return whole
    if rem > 5:
        return whole + 1
    return whole if whole % 2 == 0 else whole + 1

def luhn_checksum_valid(digits):
    if len(digits) == 0:
        return False
    total = 0
    for i, ch in enumerate(reversed(digits)):
        d = int(ch)
        if i % 2 == 1:
            d *= 2
            if d > 9:
                d -= 9
        total += d
    return total % 10 == 0

def password_rule_count(password):
    count = 0
    if len(password) >= 8:
        count += 1
    if any(c.isupper() for c in password):
        count += 1
    if any(c.islower() for c in password):
        count += 1
    if any(c.isdigit() for c in password):
        count += 1
    if any(c in "!@#$%^&*" for c in password):
        count += 1
    return count

def clamp_range(value, lo, hi):
    if lo > hi:
        lo, hi = hi, lo
    if value < lo:
        return lo
    if value > hi:
        return hi
    return value

def isbn10_checksum_valid(isbn):
    cleaned = isbn.replace('-', '')
    if len(cleaned) != 10:
        return False
    if not cleaned[:9].isdigit():
        return False
    last = cleaned[9]
    if not (last.isdigit() or last == 'X'):
        return False
    total = 0
    for i, ch in enumerate(cleaned):
        val = 10 if ch == 'X' else int(ch)
        total += val * (i + 1)
    return total % 11 == 0

def stable_dedup(items):
