def merge_intervals(intervals):
    if not intervals:
        return []
    ordered = sorted(intervals, key=lambda iv: (iv[0], iv[1]))
    merged = [list(ordered[0])]
    for start, end in ordered[1:]:
        if start <= merged[-1][1]:
            merged[-1][1] = max(merged[-1][1], end)
        else:
            merged.append([start, end])
    return merged

def free_slots(day_start, day_end, busy):
    if day_start >= day_end:
        return []
    ivs = sorted(
        (max(s, day_start), min(e, day_end))
        for s, e in busy
        if max(s, day_start) < min(e, day_end)
    )
    gaps = []
    cursor = day_start
    for s, e in ivs:
        if s > cursor:
            gaps.append([cursor, s])
        cursor = max(cursor, e)
    if cursor < day_end:
        gaps.append([cursor, day_end])
    return gaps

def count_booking_conflicts(bookings):
    n = len(bookings)
    count = 0
    for i in range(n):
        s1, e1 = bookings[i]
        for j in range(i + 1, n):
            s2, e2 = bookings[j]
            if s1 < e2 and s2 < e1:
                count += 1
    return count

def longest_common_prefix(strings):
    if not strings:
        return ""
    prefix = strings[0]
    for s in strings[1:]:
        i = 0
        while i < len(prefix) and i < len(s) and prefix[i] == s[i]:
            i += 1
        prefix = prefix[:i]
        if not prefix:
            return ""
    return prefix

def longest_unique_substring_length(s):
    last_seen = {}
    start = 0
    best = 0
    for i, ch in enumerate(s):
        if ch in last_seen and last_seen[ch] >= start:
            start = last_seen[ch] + 1
        last_seen[ch] = i
        best = max(best, i - start + 1)
    return best

def max_window_sum(nums, k):
    n = len(nums)
    if k <= 0 or k > n:
        raise ValueError("invalid window size")
    window = sum(nums[:k])
    best = window
    for i in range(k, n):
        window += nums[i] - nums[i - k]
        best = max(best, window)
    return best

