def is_one_edit_apart(a, b):
    la, lb = len(a), len(b)
    if abs(la - lb) > 1:
        return False
    if la == lb:
        diffs = sum(1 for x, y in zip(a, b) if x != y)
        return diffs <= 1
    if la > lb:
        a, b = b, a
        la, lb = lb, la
    i = j = 0
    found_diff = False
    while i < la and j < lb:
        if a[i] != b[j]:
            if found_diff:
                return False
            found_diff = True
            j += 1
        else:
            i += 1
            j += 1
    return True

def int_to_base_n(n, base):
    digits = "0123456789abcdefghijklmnopqrstuvwxyz"
    if base < 2 or base > 36:
        raise ValueError("invalid base")
    if n < 0:
        raise ValueError("n must be non-negative")
    if n == 0:
        return "0"
    out = []
    while n > 0:
        out.append(digits[n % base])
        n //= base
    return "".join(reversed(out))

